SELECT 
FROM sys_traffic_monitor


        AND source_ip LIKE CONCAT('%', #{sourceIp}, '%')


        AND target_ip LIKE CONCAT('%', #{targetIp}, '%')


        AND http_method = #{httpMethod}


        AND request_uri LIKE CONCAT('%', #{requestUri}, '%')


        AND request_time >= #{startTime}


        AND request_time <= #{endTime}




        ORDER BY ${orderBy}


        ORDER BY id DESC


LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM sys_traffic_monitor


        AND source_ip LIKE CONCAT('%', #{sourceIp}, '%')


        AND target_ip LIKE CONCAT('%', #{targetIp}, '%')


        AND http_method = #{httpMethod}


        AND request_uri LIKE CONCAT('%', #{requestUri}, '%')


        AND request_time >= #{startTime}


        AND request_time <= #{endTime}

SELECT COALESCE(SUM(request_count), 0)
FROM sys_traffic_monitor


        AND source_ip LIKE CONCAT('%', #{sourceIp}, '%')


        AND target_ip LIKE CONCAT('%', #{targetIp}, '%')


        AND http_method = #{httpMethod}


        AND request_uri LIKE CONCAT('%', #{requestUri}, '%')


        AND request_time >= #{startTime}


        AND request_time <= #{endTime}
